package cobra

import "testing"

func TestCommandPathWithVersion(t *testing.T) {
	root := &Command{
		Use: "root",
		Version: "1.0.0",
	}
	sub := &Command{
		Use: "sub",
		Version: "2.0.0",
	}
	root.AddCommand(sub)

	// Without IncludeVersionInPath
	if path := root.CommandPath(); path != "root" {
		t.Errorf("Expected 'root', got '%s'", path)
	}
	if path := sub.CommandPath(); path != "root sub" {
		t.Errorf("Expected 'root sub', got '%s'", path)
	}

	// With IncludeVersionInPath
	root.IncludeVersionInPath = true
	sub.IncludeVersionInPath = true

	if path := root.CommandPath(); path != "root@1.0.0" {
		t.Errorf("Expected 'root@1.0.0', got '%s'", path)
	}
	if path := sub.CommandPath(); path != "root@1.0.0 sub@2.0.0" {
		t.Errorf("Expected 'root@1.0.0 sub@2.0.0', got '%s'", path)
	}
}

func TestCommandPathWithSeparator(t *testing.T) {
	root := &Command{
		Use: "root",
		PathSeparator: ":",
	}
	sub := &Command{
		Use: "sub",
		PathSeparator: ":",
	}
	root.AddCommand(sub)

	if path := root.CommandPath(); path != "root" {
		t.Errorf("Expected 'root', got '%s'", path)
	}
	if path := sub.CommandPath(); path != "root:sub" {
		t.Errorf("Expected 'root:sub', got '%s'", path)
	}
}

func TestCommandPathWithVersionAndSeparator(t *testing.T) {
	root := &Command{
		Use: "root",
		Version: "1.0.0",
		PathSeparator: ":",
		IncludeVersionInPath: true,
	}
	sub := &Command{
		Use: "sub",
		Version: "2.0.0",
		PathSeparator: ":",
		IncludeVersionInPath: true,
	}
	root.AddCommand(sub)

	if path := root.CommandPath(); path != "root@1.0.0" {
		t.Errorf("Expected 'root@1.0.0', got '%s'", path)
	}
	if path := sub.CommandPath(); path != "root@1.0.0:sub@2.0.0" {
		t.Errorf("Expected 'root@1.0.0:sub@2.0.0', got '%s'", path)
	}
}
EOF

