func TestCommandPathEdgeCases(t *testing.T) {
	// Test 1: Empty PathSeparator should use default space
	root1 := &Command{Use: "root"}
	sub1 := &Command{Use: "sub"}
	root1.AddCommand(sub1)
	if path := sub1.CommandPath(); path != "root sub" {
		t.Errorf("Expected 'root sub', got '%s'", path)
	}

	// Test 2: IncludeVersionInPath true but no version
	root2 := &Command{Use: "root", IncludeVersionInPath: true}
	if path := root2.CommandPath(); path != "root" {
		t.Errorf("Expected 'root', got '%s'", path)
	}

	// Test 3: Custom separator on parent only (should propagate? Let me check behavior)
	root3 := &Command{Use: "root", PathSeparator: ":"}
	sub3 := &Command{Use: "sub"}  // no PathSeparator
	root3.AddCommand(sub3)
	// The separator is checked on the child command, so this should use default space
	if path := sub3.CommandPath(); path != "root sub" {
		t.Errorf("Expected 'root sub' (child separator), got '%s'", path)
	}

	// Test 4: Multi-level hierarchy with mixed settings
	root4 := &Command{Use: "root", Version: "1.0.0", IncludeVersionInPath: true}
	mid := &Command{Use: "mid"}
	sub4 := &Command{Use: "sub", Version: "3.0.0", IncludeVersionInPath: true}
	root4.AddCommand(mid)
	mid.AddCommand(sub4)

	if path := root4.CommandPath(); path != "root@1.0.0" {
		t.Errorf("Expected 'root@1.0.0', got '%s'", path)
	}
	if path := mid.CommandPath(); path != "root@1.0.0 mid" {
		t.Errorf("Expected 'root@1.0.0 mid', got '%s'", path)
	}
	if path := sub4.CommandPath(); path != "root@1.0.0 mid sub@3.0.0" {
		t.Errorf("Expected 'root@1.0.0 mid sub@3.0.0', got '%s'", path)
	}

	// Test 5: All levels with custom separator and version
	root5 := &Command{Use: "root", Version: "1.0.0", PathSeparator: ">", IncludeVersionInPath: true}
	mid5 := &Command{Use: "mid", Version: "2.0.0", PathSeparator: ">", IncludeVersionInPath: true}
	sub5 := &Command{Use: "sub", Version: "3.0.0", PathSeparator: ">", IncludeVersionInPath: true}
	root5.AddCommand(mid5)
	mid5.AddCommand(sub5)

